import{_ as a,c as o,o as r,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"许可证: BSL条款说明 | Plannotator","description":"学习 Plannotator 的 Business Source License 1.1 (BSL) 许可证条款和商业使用限制。了解允许的使用场景、未来变更计划及 2030 年转为 Apache 2.0 的时间表。","frontmatter":{"title":"许可证: BSL条款说明 | Plannotator","sidebarTitle":"了解商业使用规则","subtitle":"许可证: BSL条款说明","description":"学习 Plannotator 的 Business Source License 1.1 (BSL) 许可证条款和商业使用限制。了解允许的使用场景、未来变更计划及 2030 年转为 Apache 2.0 的时间表。","tags":["许可证","BSL-1.1","商业使用"],"prerequisite":[],"order":3},"headers":[],"relativePath":"zh/backnotprop/plannotator/appendix/license/index.md","filePath":"zh/backnotprop/plannotator/appendix/license/index.md"}'),n={name:"zh/backnotprop/plannotator/appendix/license/index.md"};function e(i,t,s,d,h,p){return r(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="plannotator-许可证说明" tabindex="-1">Plannotator 许可证说明 <a class="header-anchor" href="#plannotator-许可证说明" aria-label="Permalink to &quot;Plannotator 许可证说明&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>了解 Plannotator 使用的许可证类型和核心条款</li><li>明确哪些使用场景是被允许的，哪些是受限的</li><li>知道许可证的未来变更时间表</li><li>了解如何获取商业许可或联系授权方</li></ul><h2 id="你现在需要了解" tabindex="-1">你现在需要了解 <a class="header-anchor" href="#你现在需要了解" aria-label="Permalink to &quot;你现在需要了解&quot;">​</a></h2><p>Plannotator 采用 <strong>Business Source License 1.1 (BSL)</strong> 作为其开源许可证。这是一种特殊的许可证，旨在在保护商业价值的同时，最终让项目完全开源。</p><h2 id="核心条款" tabindex="-1">核心条款 <a class="header-anchor" href="#核心条款" aria-label="Permalink to &quot;核心条款&quot;">​</a></h2><h3 id="许可证类型" tabindex="-1">许可证类型 <a class="header-anchor" href="#许可证类型" aria-label="Permalink to &quot;许可证类型&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>许可证名称</strong></td><td>Business Source License 1.1 (BSL)</td></tr><tr><td><strong>版权方</strong></td><td>backnotprop (2025)</td></tr><tr><td><strong>授权项目</strong></td><td>plannotator</td></tr><tr><td><strong>变更日期</strong></td><td>2030-01-01</td></tr><tr><td><strong>变更后许可证</strong></td><td>Apache License, Version 2.0</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">什么是 BSL？</p><p>Business Source License 是一种由 MariaDB 开发的特殊许可证。它在短期内限制了某些商业用途，但承诺在特定日期后将软件转换为完全开源的许可证（如 Apache 2.0）。这种模式让开源项目能够在商业化过程中获得可持续的收益，同时确保长期对社区开放。</p></div><h3 id="允许的使用方式" tabindex="-1">允许的使用方式 <a class="header-anchor" href="#允许的使用方式" aria-label="Permalink to &quot;允许的使用方式&quot;">​</a></h3><p>根据 BSL 1.1 条款，你可以：</p><ul><li><p>✅ <strong>复制、修改和创建衍生作品</strong></p><ul><li>你可以基于 Plannotator 进行二次开发</li><li>可以修改源代码以适应你的需求</li></ul></li><li><p>✅ <strong>重新分发</strong></p><ul><li>可以分发原始或修改后的版本</li><li>必须保留原始的许可证声明</li></ul></li><li><p>✅ <strong>非生产环境使用</strong></p><ul><li>内部开发、测试和评估</li><li>个人学习和研究</li></ul></li></ul><div class="tip custom-block"><p class="custom-block-title">个人和企业内部的广泛使用</p><p>BSL 对&quot;非生产环境使用&quot;的定义很宽泛，包括个人和公司内部的各种场景。你和你的团队成员（包括独立承包商）都可以自由使用 Plannotator 进行开发、测试和部署。</p></div><h3 id="使用限制-重要" tabindex="-1">使用限制（重要！） <a class="header-anchor" href="#使用限制-重要" aria-label="Permalink to &quot;使用限制（重要！）&quot;">​</a></h3><p><strong>核心限制</strong>：不得将 Plannotator 用于 <strong>计划、上下文或审批服务（Planning, Context, or Approval Service）</strong>。</p><h4 id="什么是-计划、上下文或审批服务" tabindex="-1">什么是&quot;计划、上下文或审批服务&quot;？ <a class="header-anchor" href="#什么是-计划、上下文或审批服务" aria-label="Permalink to &quot;什么是&quot;计划、上下文或审批服务&quot;？&quot;">​</a></h4><p>任何允许<strong>第三方</strong>（除员工和独立承包商外）通过直接或间接操作访问 Plannotator 功能的商业产品，都属于受限服务。具体包括但不限于：</p><ul><li><p><strong>云服务提供商</strong></p><ul><li>SaaS 平台提供 Plannotator 功能作为其服务的一部分</li><li>托管服务提供商向客户或订阅者提供 Plannotator</li></ul></li><li><p><strong>基础设施服务</strong></p><ul><li>数据中心服务提供商</li><li>云计算平台提供商</li></ul></li><li><p><strong>类似服务的第三方</strong></p><ul><li>包括上述实体及其关联公司提供的任何服务</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">商业使用警告</p><p>如果你计划将 Plannotator 作为商业服务的一部分提供给第三方使用，必须提前获取商业许可。违反此条款将自动终止你对当前及所有版本 Plannotator 的使用权利。</p></div><h2 id="许可证变更时间表" tabindex="-1">许可证变更时间表 <a class="header-anchor" href="#许可证变更时间表" aria-label="Permalink to &quot;许可证变更时间表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时间节点</th><th>许可证类型</th><th>说明</th></tr></thead><tbody><tr><td><strong>当前 - 2030-01-01</strong></td><td>BSL 1.1</td><td>受限的开源许可证</td></tr><tr><td><strong>2030-01-01 起</strong></td><td>Apache 2.0</td><td>完全开源，无商业限制</td></tr></tbody></table><h3 id="变更后会发生什么" tabindex="-1">变更后会发生什么？ <a class="header-anchor" href="#变更后会发生什么" aria-label="Permalink to &quot;变更后会发生什么？&quot;">​</a></h3><p>从 2030 年 1 月 1 日起，Plannotator 将自动转换为 <strong>Apache License 2.0</strong>。这意味着：</p><ul><li>✅ 所有商业限制将取消</li><li>✅ 可以自由地用于任何商业目的</li><li>✅ 可以将其集成到任何 SaaS 服务中</li><li>✅ 符合宽松的开源许可证标准</li></ul><h2 id="商业许可" tabindex="-1">商业许可 <a class="header-anchor" href="#商业许可" aria-label="Permalink to &quot;商业许可&quot;">​</a></h2><p>如果你需要在不遵守 BSL 限制的情况下使用 Plannotator（例如用于计划、上下文或审批服务），可以：</p><ol><li><p><strong>购买商业许可</strong></p><ul><li>从 backnotprop 或其授权经销商购买</li><li>获得不受 BSL 限制的使用权利</li></ul></li><li><p><strong>联系授权方</strong></p><ul><li>发邮件至：backnotprop</li><li>说明你的使用场景和需求</li></ul></li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="我可以在公司内部使用-plannotator-吗" tabindex="-1">我可以在公司内部使用 Plannotator 吗？ <a class="header-anchor" href="#我可以在公司内部使用-plannotator-吗" aria-label="Permalink to &quot;我可以在公司内部使用 Plannotator 吗？&quot;">​</a></h3><p><strong>可以。</strong> BSL 明确允许你和你的员工、独立承包商使用 Plannotator 进行内部开发、测试和部署。限制仅适用于向<strong>第三方</strong>（非员工和承包商）提供服务的场景。</p><h3 id="我可以基于-plannotator-开发自己的产品吗" tabindex="-1">我可以基于 Plannotator 开发自己的产品吗？ <a class="header-anchor" href="#我可以基于-plannotator-开发自己的产品吗" aria-label="Permalink to &quot;我可以基于 Plannotator 开发自己的产品吗？&quot;">​</a></h3><p><strong>可以，但有条件。</strong> 如果你的产品是：</p><ul><li>内部工具：✅ 允许</li><li>个人项目：✅ 允许</li><li>开源项目：✅ 允许（保留 BSL 许可证）</li><li>商业产品：❓ 需要评估是否属于&quot;计划、上下文或审批服务&quot;</li></ul><h3 id="我的公司是-saas-提供商-可以使用吗" tabindex="-1">我的公司是 SaaS 提供商，可以使用吗？ <a class="header-anchor" href="#我的公司是-saas-提供商-可以使用吗" aria-label="Permalink to &quot;我的公司是 SaaS 提供商，可以使用吗？&quot;">​</a></h3><p><strong>需要商业许可。</strong> 如果你的 SaaS 产品将 Plannotator 的功能提供给客户使用（即使作为功能的一部分），这属于受限的商业服务，必须购买商业许可。</p><h3 id="_2030-年之后我可以将-plannotator-用于任何用途吗" tabindex="-1">2030 年之后我可以将 Plannotator 用于任何用途吗？ <a class="header-anchor" href="#_2030-年之后我可以将-plannotator-用于任何用途吗" aria-label="Permalink to &quot;2030 年之后我可以将 Plannotator 用于任何用途吗？&quot;">​</a></h3><p><strong>是的。</strong> 从变更日期起，Plannotator 将采用 Apache 2.0 许可证，所有商业限制都将取消，你可以自由地用于任何用途。</p><h2 id="许可证完整文本" tabindex="-1">许可证完整文本 <a class="header-anchor" href="#许可证完整文本" aria-label="Permalink to &quot;许可证完整文本&quot;">​</a></h2><p>完整的 Business Source License 1.1 文本请参阅项目根目录的 <code>LICENSE</code> 文件。</p><h2 id="联系方式" tabindex="-1">联系方式 <a class="header-anchor" href="#联系方式" aria-label="Permalink to &quot;联系方式&quot;">​</a></h2><p>如需商业许可或有其他问题，请联系：</p><ul><li><strong>授权方</strong>：backnotprop</li><li><strong>项目仓库</strong>：<a href="https://github.com/backnotprop/plannotator" target="_blank" rel="noreferrer">backnotprop/plannotator</a></li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们查看 <strong><a href="./../../changelog/release-notes/">更新日志</a></strong>。</p><p>你会看到：</p><ul><li>Plannotator 的版本历史</li><li>每个版本的新功能和改进</li><li>重要的 bug 修复</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>许可证声明</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/README.md#L100-L104" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>100-104</td></tr><tr><td>完整许可证文本</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/LICENSE" target="_blank" rel="noreferrer"><code>LICENSE</code></a></td><td>1-115</td></tr></tbody></table><p><strong>关键信息</strong>：</p><ul><li>许可证类型：Business Source License 1.1 (BSL)</li><li>版权方：backnotprop (c) 2025</li><li>变更日期：2030-01-01</li><li>变更后许可证：Apache License, Version 2.0</li><li>主要限制：不得用于计划、上下文或审批服务</li></ul></details>',47)])])}const b=a(n,[["render",e]]);export{u as __pageData,b as default};
